"use strict";

(function () {
    function requireFunction(value, name) {
        if (typeof value !== "function") {
            throw new Error(`AdminWiring requires ${name}.`);
        }
    }

    function requireElement(controls, key) {
        const value = controls ? controls[key] : null;
        if (!value) {
            throw new Error(`AdminWiring requires controls.${key}.`);
        }

        return value;
    }

    function requireString(value, name) {
        if (typeof value !== "string" || value.trim().length === 0) {
            throw new Error(`AdminWiring requires ${name}.`);
        }
    }

    function createWiring(options) {
        const settings = options || {};
        const controls = settings.controls || {};
        const usersSearchInput = requireElement(controls, "usersSearchInput");
        const usersSearchApplyButton = requireElement(controls, "usersSearchApplyButton");
        const usersSearchResetButton = requireElement(controls, "usersSearchResetButton");
        const referenceTypeCodeInput = requireElement(controls, "referenceTypeCodeInput");
        const referenceActiveOnlyCheckbox = requireElement(controls, "referenceActiveOnlyCheckbox");
        const referenceLoadButton = requireElement(controls, "referenceLoadButton");
        const referenceOpenApiLink = requireElement(controls, "referenceOpenApiLink");

        const referenceApiRoot = settings.referenceApiRoot;
        requireString(referenceApiRoot, "referenceApiRoot");

        const normalizeTypeCode = settings.normalizeTypeCode;
        const buildReferenceItemsUrl = settings.buildReferenceItemsUrl;
        const setReferenceStatus = settings.setReferenceStatus;
        const onUsersRefreshRequested = settings.onUsersRefreshRequested;
        const onReferenceRefreshRequested = settings.onReferenceRefreshRequested;
        const invalidReferenceTypeMessage = settings.invalidReferenceTypeMessage || "Некорректный код типа.";
        requireFunction(normalizeTypeCode, "normalizeTypeCode");
        requireFunction(buildReferenceItemsUrl, "buildReferenceItemsUrl");
        requireFunction(setReferenceStatus, "setReferenceStatus");
        requireFunction(onUsersRefreshRequested, "onUsersRefreshRequested");
        requireFunction(onReferenceRefreshRequested, "onReferenceRefreshRequested");

        let currentUsersSearch = "";
        let currentReferenceTypeCode = "";
        let currentReferenceActiveOnly = false;
        let isBound = false;

        function updateReferenceApiLink() {
            referenceOpenApiLink.href = buildReferenceItemsUrl(
                referenceApiRoot,
                currentReferenceTypeCode,
                currentReferenceActiveOnly);
        }

        function applyUsersSearch() {
            currentUsersSearch = String(usersSearchInput.value ?? "").trim();
            onUsersRefreshRequested();
        }

        function resetUsersSearch() {
            usersSearchInput.value = "";
            currentUsersSearch = "";
            onUsersRefreshRequested();
        }

        function applyReferenceType() {
            try {
                currentReferenceTypeCode = normalizeTypeCode(referenceTypeCodeInput.value);
                currentReferenceActiveOnly = Boolean(referenceActiveOnlyCheckbox.checked);
                referenceTypeCodeInput.value = currentReferenceTypeCode;
                updateReferenceApiLink();
                onReferenceRefreshRequested();
            } catch (error) {
                const message = error && error.message
                    ? error.message
                    : invalidReferenceTypeMessage;
                setReferenceStatus(message, true);
            }
        }

        function bindEvents() {
            if (isBound) {
                return;
            }

            usersSearchApplyButton.addEventListener("click", applyUsersSearch);
            usersSearchResetButton.addEventListener("click", resetUsersSearch);
            usersSearchInput.addEventListener("keydown", function (event) {
                if (event.key === "Enter") {
                    event.preventDefault();
                    applyUsersSearch();
                }
            });

            referenceLoadButton.addEventListener("click", applyReferenceType);
            referenceTypeCodeInput.addEventListener("keydown", function (event) {
                if (event.key === "Enter") {
                    event.preventDefault();
                    applyReferenceType();
                }
            });
            referenceActiveOnlyCheckbox.addEventListener("change", applyReferenceType);

            isBound = true;
        }

        function initialize() {
            currentUsersSearch = String(usersSearchInput.value ?? "").trim();
            currentReferenceTypeCode = normalizeTypeCode(referenceTypeCodeInput.value || "PURCHASE_TYPE");
            currentReferenceActiveOnly = Boolean(referenceActiveOnlyCheckbox.checked);
            referenceTypeCodeInput.value = currentReferenceTypeCode;
            updateReferenceApiLink();
        }

        return {
            initialize: initialize,
            bindEvents: bindEvents,
            getUsersSearch: function () {
                return currentUsersSearch;
            },
            getReferenceContext: function () {
                return {
                    typeCode: currentReferenceTypeCode,
                    activeOnly: currentReferenceActiveOnly
                };
            }
        };
    }

    const exportsObject = {
        createWiring: createWiring
    };

    if (typeof window !== "undefined") {
        window.AdminWiring = exportsObject;
    }

    if (typeof module !== "undefined" && module.exports) {
        module.exports = exportsObject;
    }
})();

/* Source: admin-bootstrap.js */
"use strict";

(function () {
    const REQUIRED_CONTROLS = {
        usersGridElement: "[data-admin-users-grid]",
        usersStatusElement: "[data-admin-users-status]",
        usersSearchInput: "[data-admin-users-search]",
        usersSearchApplyButton: "[data-admin-users-search-apply]",
        usersSearchResetButton: "[data-admin-users-search-reset]",
        rolesGridElement: "[data-admin-roles-grid]",
        rolesStatusElement: "[data-admin-roles-status]",
        referenceGridElement: "[data-admin-reference-grid]",
        referenceStatusElement: "[data-admin-reference-status]",
        referenceTypeCodeInput: "[data-admin-reference-type-code]",
        referenceActiveOnlyCheckbox: "[data-admin-reference-active-only]",
        referenceLoadButton: "[data-admin-reference-load]",
        referenceOpenApiLink: "[data-admin-reference-open-api]"
    };

    const REQUIRED_MODULES = [
        {
            key: "adminMessagesRoot",
            moduleName: "AdminMessages",
            factoryName: "createMessages"
        },
        {
            key: "adminHelpersRoot",
            moduleName: "AdminHelpers",
            factoryName: "createHelpers"
        },
        {
            key: "adminApiRoot",
            moduleName: "AdminApi",
            factoryName: "createApiClient"
        },
        {
            key: "adminRuntimeRoot",
            moduleName: "AdminRuntime",
            factoryName: "createRuntime"
        },
        {
            key: "adminGridsRoot",
            moduleName: "AdminGrids",
            factoryName: "createGrids"
        },
        {
            key: "adminWiringRoot",
            moduleName: "AdminWiring",
            factoryName: "createWiring"
        }
    ];

    function setSectionStatus(element, message, isError) {
        if (!element) {
            return;
        }

        element.textContent = message;
        if (element.classList && typeof element.classList.toggle === "function") {
            element.classList.toggle("admin-status--error", Boolean(isError));
            return;
        }

        if (Boolean(isError) && element.classList && typeof element.classList.add === "function") {
            element.classList.add("admin-status--error");
        }
    }

    function reportStatusErrors(statusElements, message, logError) {
        setSectionStatus(statusElements.usersStatusElement, message, true);
        setSectionStatus(statusElements.rolesStatusElement, message, true);
        setSectionStatus(statusElements.referenceStatusElement, message, true);

        if (typeof logError === "function") {
            logError(message);
        }
    }

    function resolveControls(moduleRoot) {
        const controls = {};
        const entries = Object.entries(REQUIRED_CONTROLS);
        for (let index = 0; index < entries.length; index += 1) {
            const key = entries[index][0];
            const selector = entries[index][1];
            const value = moduleRoot.querySelector(selector);
            if (!value) {
                return null;
            }

            controls[key] = value;
        }

        return controls;
    }

    function resolveModuleRoots(win, statusElements, logError) {
        const roots = {};
        for (let index = 0; index < REQUIRED_MODULES.length; index += 1) {
            const module = REQUIRED_MODULES[index];
            const moduleRoot = win[module.moduleName];
            if (!moduleRoot || typeof moduleRoot[module.factoryName] !== "function") {
                reportStatusErrors(
                    statusElements,
                    `Скрипт ${module.moduleName} не загружен. Проверьте порядок подключения скриптов.`,
                    logError);
                return null;
            }

            roots[module.key] = moduleRoot;
        }

        return roots;
    }

    function createBootstrapContext(options) {
        const settings = options || {};
        const doc = settings.document || (typeof document !== "undefined" ? document : null);
        const win = settings.window || (typeof window !== "undefined" ? window : {});
        const logError = settings.logError;

        if (!doc || typeof doc.querySelector !== "function") {
            throw new Error("Admin bootstrap requires a document with querySelector.");
        }

        const moduleRoot = doc.querySelector("[data-admin-module]");
        if (!moduleRoot) {
            return null;
        }

        const controls = resolveControls(moduleRoot);
        if (!controls) {
            return null;
        }

        const statusElements = {
            usersStatusElement: controls.usersStatusElement,
            rolesStatusElement: controls.rolesStatusElement,
            referenceStatusElement: controls.referenceStatusElement
        };

        if (!(win.jQuery && win.DevExpress && win.DevExpress.data)) {
            reportStatusErrors(statusElements, "Скрипты DevExpress не загружены. Проверьте доступ к UI-ассетам (CDN или локальный режим).", logError);
            return null;
        }

        const moduleRoots = resolveModuleRoots(win, statusElements, logError);
        if (!moduleRoots) {
            return null;
        }

        const endpoints = {
            usersEndpoint: moduleRoot.getAttribute("data-users-api-endpoint") || "/api/admin/users",
            rolesEndpoint: moduleRoot.getAttribute("data-roles-api-endpoint") || "/api/admin/roles",
            referenceApiRoot: moduleRoot.getAttribute("data-reference-api-root") || "/api/reference-data"
        };

        return {
            moduleRoot: moduleRoot,
            endpoints: endpoints,
            controls: controls,
            moduleRoots: moduleRoots
        };
    }

    const exportsObject = {
        createBootstrapContext: createBootstrapContext
    };

    if (typeof window !== "undefined") {
        window.AdminBootstrap = exportsObject;
    }

    if (typeof module !== "undefined" && module.exports) {
        module.exports = exportsObject;
    }
})();

/* Source: admin-grid-background-refresh.js */
"use strict";

(function () {
    function createBackgroundReferenceRefresh(options) {
        const settings = options || {};
        const windowRef = settings.windowRef;
        const documentRef = settings.documentRef;
        const setSectionStatus = settings.setSectionStatus;
        const getReferenceGridInstance = settings.getReferenceGridInstance;
        const referenceStatusElement = settings.referenceStatusElement;
        const referenceLoadingMessage = settings.referenceLoadingMessage;
        const referenceOperationErrorMessage = settings.referenceOperationErrorMessage;

        function runAfterWindowLoad(callback) {
            if (typeof callback !== "function") {
                return;
            }

            if (documentRef && documentRef.readyState === "complete") {
                callback();
                return;
            }

            if (windowRef && typeof windowRef.addEventListener === "function") {
                windowRef.addEventListener("load", function () {
                    callback();
                }, { once: true });
                return;
            }

            callback();
        }

        function refreshReferenceGridInBackground() {
            const referenceGridInstance = typeof getReferenceGridInstance === "function"
                ? getReferenceGridInstance()
                : null;

            if (!referenceGridInstance || typeof referenceGridInstance.refresh !== "function") {
                return;
            }

            setSectionStatus(referenceStatusElement, referenceLoadingMessage(), false);
            runAfterWindowLoad(function () {
                Promise.resolve().then(function () {
                    return referenceGridInstance.refresh();
                }).catch(function (error) {
                    const message = error && error.message
                        ? error.message
                        : referenceOperationErrorMessage();
                    setSectionStatus(referenceStatusElement, message, true);
                });
            });
        }

        return {
            refreshReferenceGridInBackground: refreshReferenceGridInBackground
        };
    }

    const exportsObject = {
        createBackgroundReferenceRefresh: createBackgroundReferenceRefresh
    };

    if (typeof window !== "undefined") {
        window.AdminGridBackgroundRefresh = exportsObject;
    }

    if (typeof module !== "undefined" && module.exports) {
        module.exports = exportsObject;
    }
})();

/* Source: admin-grid.js */
"use strict";

(function () {
    const adminBootstrapRoot = window.AdminBootstrap;
    if (!adminBootstrapRoot || typeof adminBootstrapRoot.createBootstrapContext !== "function") {
        return;
    }

    const context = adminBootstrapRoot.createBootstrapContext({
        document: document,
        window: window,
        logError: function (message) {
            if (window.console && typeof window.console.error === "function") {
                window.console.error(message);
            }
        }
    });

    if (!context) {
        return;
    }

    const endpoints = context.endpoints;
    const controls = context.controls;
    const moduleRoots = context.moduleRoots;

    const usersStatusElement = controls.usersStatusElement;
    const rolesStatusElement = controls.rolesStatusElement;
    const referenceStatusElement = controls.referenceStatusElement;

    function setSectionStatus(element, message, isError) {
        element.textContent = message;
        element.classList.toggle("admin-status--error", Boolean(isError));
    }

    function resolveBackgroundRefreshModule() {
        if (window.AdminGridBackgroundRefresh
            && typeof window.AdminGridBackgroundRefresh.createBackgroundReferenceRefresh === "function") {
            return window.AdminGridBackgroundRefresh;
        }

        if (typeof module !== "undefined" && module.exports && typeof require === "function") {
            return require("./admin-grid-background-refresh.js");
        }

        throw new Error("AdminGrid requires 'AdminGridBackgroundRefresh.createBackgroundReferenceRefresh'.");
    }

    const messages = moduleRoots.adminMessagesRoot.createMessages();
    const helpers = moduleRoots.adminHelpersRoot.createHelpers();
    const apiClient = moduleRoots.adminApiRoot.createApiClient({
        usersEndpoint: endpoints.usersEndpoint,
        rolesEndpoint: endpoints.rolesEndpoint,
        referenceApiRoot: endpoints.referenceApiRoot,
        parseErrorBody: helpers.parseErrorBody
    });

    let usersGridInstance = null;
    let referenceGridInstance = null;
    let rolesDataSource = [];

    const wiring = moduleRoots.adminWiringRoot.createWiring({
        controls: {
            usersSearchInput: controls.usersSearchInput,
            usersSearchApplyButton: controls.usersSearchApplyButton,
            usersSearchResetButton: controls.usersSearchResetButton,
            referenceTypeCodeInput: controls.referenceTypeCodeInput,
            referenceActiveOnlyCheckbox: controls.referenceActiveOnlyCheckbox,
            referenceLoadButton: controls.referenceLoadButton,
            referenceOpenApiLink: controls.referenceOpenApiLink
        },
        referenceApiRoot: endpoints.referenceApiRoot,
        normalizeTypeCode: helpers.normalizeTypeCode,
        buildReferenceItemsUrl: helpers.buildReferenceItemsUrl,
        invalidReferenceTypeMessage: messages.invalidReferenceType(),
        setReferenceStatus: function (message, isError) {
            setSectionStatus(referenceStatusElement, message, isError);
        },
        onUsersRefreshRequested: function () {
            if (usersGridInstance && typeof usersGridInstance.refresh === "function") {
                usersGridInstance.refresh();
            }
        },
        onReferenceRefreshRequested: function () {
            if (referenceGridInstance && typeof referenceGridInstance.refresh === "function") {
                referenceGridInstance.refresh();
            }
        }
    });

    const runtime = moduleRoots.adminRuntimeRoot.createRuntime({
        customStoreCtor: window.DevExpress.data.CustomStore,
        apiClient: apiClient,
        helpers: {
            hasOwn: helpers.hasOwn,
            normalizeRoleNames: helpers.normalizeRoleNames,
            buildReferencePayload: helpers.buildReferencePayload
        },
        messages: {
            usersLoaded: messages.usersLoaded,
            rolesLoaded: messages.rolesLoaded,
            referenceLoaded: messages.referenceLoaded,
            userUpdated: messages.userUpdated,
            referenceSaved: messages.referenceSaved,
            referenceUpdated: messages.referenceUpdated,
            referenceDeleted: messages.referenceDeleted
        },
        callbacks: {
            getUsersSearch: function () {
                return wiring.getUsersSearch();
            },
            getReferenceContext: function () {
                return wiring.getReferenceContext();
            },
            setUsersStatus: function (message, isError) {
                setSectionStatus(usersStatusElement, message, isError);
            },
            setRolesStatus: function (message, isError) {
                setSectionStatus(rolesStatusElement, message, isError);
            },
            setReferenceStatus: function (message, isError) {
                setSectionStatus(referenceStatusElement, message, isError);
            }
        }
    });

    const backgroundRefresher = resolveBackgroundRefreshModule().createBackgroundReferenceRefresh({
        windowRef: window,
        documentRef: document,
        setSectionStatus: setSectionStatus,
        getReferenceGridInstance: function () {
            return referenceGridInstance;
        },
        referenceStatusElement: referenceStatusElement,
        referenceLoadingMessage: messages.referenceLoading,
        referenceOperationErrorMessage: messages.referenceOperationError
    });

    function initializeGrids() {
        return moduleRoots.adminGridsRoot.createGrids({
            jQueryImpl: window.jQuery,
            elements: {
                usersGridElement: controls.usersGridElement,
                rolesGridElement: controls.rolesGridElement,
                referenceGridElement: controls.referenceGridElement
            },
            stores: {
                usersStore: runtime.usersStore,
                referenceStore: runtime.referenceStore
            },
            rolesDataSource: rolesDataSource,
            callbacks: {
                toStringList: helpers.toStringList,
                onUsersDataError: function (error) {
                    setSectionStatus(usersStatusElement, error?.message ?? messages.usersOperationError(), true);
                },
                onReferenceDataError: function (error) {
                    setSectionStatus(referenceStatusElement, error?.message ?? messages.referenceOperationError(), true);
                }
            }
        });
    }

    (async function bootstrap() {
        try {
            setSectionStatus(usersStatusElement, messages.usersLoading(), false);
            setSectionStatus(rolesStatusElement, messages.rolesLoading(), false);
            setSectionStatus(referenceStatusElement, messages.referenceLoading(), false);

            wiring.initialize();

            await runtime.loadRoles();
            rolesDataSource = runtime.getRoles();

            const grids = initializeGrids();
            usersGridInstance = grids.usersGridInstance;
            referenceGridInstance = grids.referenceGridInstance;

            wiring.bindEvents();

            await usersGridInstance.refresh();
            backgroundRefresher.refreshReferenceGridInBackground();
        } catch (error) {
            const message = error && error.message
                ? error.message
                : messages.bootstrapFailed();
            setSectionStatus(usersStatusElement, message, true);
            setSectionStatus(rolesStatusElement, message, true);
            setSectionStatus(referenceStatusElement, message, true);
        }
    })();
})();
